sql:
SELECT COUNT(post_id) AS neutral_post_count
FROM post_analysis
WHERE sentiment = 'neutral';

SELECT sentiment
  FROM post_analysis
  WHERE created_at LIKE '2022-01-01%';

SELECT COUNT(version_id) AS version_count
FROM post_versions
WHERE post_id = 1486232465605804033;

SELECT COUNT(media_id) AS media_count
FROM post_media
WHERE post_id = 1486210376534573058;

SELECT version_id
FROM post_versions
WHERE created_at > '2022-01-01';

SELECT post_id, media_type, media_url
FROM post_media
WHERE media_type = 'image';

SELECT url_id, post_id, url
FROM post_urls
WHERE post_id = 1486375506912104452;

SELECT post_id, COUNT(url_id) AS url_count
FROM post_urls
GROUP BY post_id;

external_knowledge:
Data analyst refers to a user with the role name 'data analyst'; 
Top 3 most recent posts are determined by the 'created_at' timestamp in descending order; 
Negative posts are determined by the sentiment column with a value of 'negative'.

